New greedy insertion with regret-based scoring prioritizing time window feasibility and minimizing detour distance increase, attempting insertions across all existing assigns plus one potential empty assign per iteration, falling back to forced insertion into the first feasible empty slot if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		isEmpty   bool
	}
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	nextAssignIdx := dispatch.AssignsLen
	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		bestCandidate := candidate{costDelta: 1e18, isEmpty: false}
		fallbackEmpty := -1
		for ai := 0; ai <= nextAssignIdx && ai < MAXASSIGNS; ai++ {
			isEmptySlot := ai >= dispatch.AssignsLen
			if isEmptySlot && fallbackEmpty == -1 {
				fallbackEmpty = ai
			}
			oldCost := dispatch.Assigns[ai].Cost
			shipId := total_ship + orderIdx
			ok := dispatch.Assigns[ai].AddShip(shipId, oris[orderIdx], dess[orderIdx])
			if ok {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					regretFactor := 0.5
					if delta < bestCandidate.costDelta*(1.0-regretFactor) || (delta < bestCandidate.costDelta*1.01 && !bestCandidate.isEmpty && isEmptySlot) {
						bestCandidate.assignIdx = ai
						bestCandidate.costDelta = delta
						bestCandidate.isEmpty = isEmptySlot
					}
				}
				dispatch.Assigns[ai].RemoveShip(shipId)
				dispatch.Assigns[ai].GenRoute()
			}
		}
		finalAi := -1
		if bestCandidate.costDelta < 1e17 {
			finalAi = bestCandidate.assignIdx
			ok := dispatch.Assigns[finalAi].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
			if !ok {
				finalAi = -1
			} else {
				dispatch.Assigns[finalAi].GenRoute()
				if dispatch.Assigns[finalAi].Cost < 0 {
					dispatch.Assigns[finalAi].RemoveShip(total_ship + orderIdx)
					dispatch.Assigns[finalAi].GenRoute()
					finalAi = -1
				}
			}
		}
		if finalAi == -1 {
			for ai := 0; ai < MAXASSIGNS; ai++ {
				isEmptySlot := ai >= dispatch.AssignsLen
				if !isEmptySlot && dispatch.Assigns[ai].StationsLen > 0 {
					continue
				}
				ok := dispatch.Assigns[ai].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
				if ok {
					dispatch.Assigns[ai].GenRoute()
					if dispatch.Assigns[ai].Cost >= 0 {
						finalAi = ai
						break
					} else {
						dispatch.Assigns[ai].RemoveShip(total_ship + orderIdx)
						dispatch.Assigns[ai].GenRoute()
					}
				}
			}
		}
		if finalAi >= 0 {
			if finalAi >= dispatch.AssignsLen {
				dispatch.AssignsLen = finalAi + 1
				if dispatch.AssignsLen > MAXASSIGNS {
					dispatch.AssignsLen = MAXASSIGNS
				}
			}
			nextAssignIdx = dispatch.AssignsLen
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

