population.algorithm:
New algorithm uses a weighted composite score prioritizing lower marginal distance increase, tighter time windows, balanced vehicle utilization through load-aware scoring, and penalizes high-cost insertions more aggressively while preserving feasibility via fallback insertion attempts.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx       int
		score     float64
		costDelta float64
	}
	orderCnt := len(oris)
	if orderCnt != len(dess) || orderCnt == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	const (
		baseWeight      = 150.0
		loadBalWeight   = 30.0
		tightWinWeight  = 800.0
		maxAcceptDelta  = 3500.0
		safeMaxAttempts = 2
	)
	for j := 0; j < orderCnt; j++ {
		best := cand{-1, -1e100, 0}
		shipID := total_ship + j
		ori, des := oris[j], dess[j]
		winTight := 0.0
		if ori.TimeEnd > ori.TimeStart {
			winWid := float64(ori.TimeEnd - ori.TimeStart)
			winTight = tightWinWeight / (winWid + 5.0)
		}
		for a := 0; a < dispatch.AssignsLen; a++ {
			oldCost := dispatch.Assigns[a].Cost
			if dispatch.Assigns[a].AddShip(shipID, ori, des) {
				dispatch.Assigns[a].GenRoute()
				newCost := dispatch.Assigns[a].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					var loadFactor float64
					curL := 0
					if dispatch.Assigns[a].StationCurrent.ReqCode != 0 {
						curL = dispatch.Assigns[a].StationCurrent.Load
					}
					switch {
					case curL <= 3:
						loadFactor = 1.5
					case curL <= 6:
						loadFactor = 1.0
					default:
						loadFactor = 0.4
					}
					baseSc := baseWeight / (delta + 1.0)
					score := baseSc + winTight + loadFactor*loadBalWeight
					if score > best.score {
						best.idx = a
						best.score = score
						best.costDelta = delta
					}
				}
				dispatch.Assigns[a].RemoveShip(shipID)
				dispatch.Assigns[a].GenRoute()
				dispatch.Assigns[a].Cost = oldCost
			}
		}
		if best.idx >= 0 && best.costDelta <= maxAcceptDelta {
			dispatch.Assigns[best.idx].AddShip(shipID, ori, des)
			dispatch.Assigns[best.idx].GenRoute()
		} else {
			fallbackInserted := false
			attempts := 0
			for a := 0; a < dispatch.AssignsLen && !fallbackInserted && attempts < safeMaxAttempts; a++ {
				oldC := dispatch.Assigns[a].Cost
				if dispatch.Assigns[a].AddShip(shipID, ori, des) {
					dispatch.Assigns[a].GenRoute()
					if dispatch.Assigns[a].Cost >= 0 {
						fallbackInserted = true
					} else {
						dispatch.Assigns[a].RemoveShip(shipID)
						dispatch.Assigns[a].GenRoute()
						dispatch.Assigns[a].Cost = oldC
					}
				}
				attempts++
			}
			if !fallbackInserted && dispatch.AssignsLen < MAXASSIGNS {
				idx := dispatch.AssignsLen
				dispatch.Assigns[idx].AddShip(shipID, ori, des)
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[idx].RemoveShip(shipID)
					dispatch.Assigns[idx].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

