Greedy insertion with nearest neighbor heuristic based on time-window feasibility and minimal marginal cost increase, using fallback expansion if all existing routes reject.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		insertOk  bool
	}
	orderCount := len(oris)
	if orderCount != len(dess) || orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	feasibleAssignIndices := make([]int, 0, dispatch.AssignsLen+orderCount)
	for i := 0; i < dispatch.AssignsLen; i++ {
		feasibleAssignIndices = append(feasibleAssignIndices, i)
	}
	shuffledSeed := make([]int, len(feasibleAssignIndices))
	copy(shuffledSeed, feasibleAssignIndices)
	rand.Shuffle(len(shuffledSeed), func(i, j int) {
		shuffledSeed[i], shuffledSeed[j] = shuffledSeed[j], shuffledSeed[i]
	})
	baseCosts := make([]float64, len(feasibleAssignIndices))
	for idx, ai := range feasibleAssignIndices {
		baseCosts[idx] = dispatch.Assigns[ai].Cost
	}
	for oi := 0; oi < orderCount; oi++ {
		ori := oris[oi]
		des := dess[oi]
		shipID := total_ship + oi
		bestCandidate := candidate{-1, 1e300, false}
		feasibleList := make([]candidate, 0, len(feasibleAssignIndices))
		for idx, assignIdx := range feasibleAssignIndices {
			assignCopyCostBefore := dispatch.Assigns[assignIdx].Cost
			ok := dispatch.Assigns[assignIdx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[assignIdx].GenRoute()
				newCost := dispatch.Assigns[assignIdx].Cost
				delta := 0.0
				if newCost >= 0 {
					delta = newCost - baseCosts[idx]
					if delta < bestCandidate.costDelta {
						bestCandidate = candidate{assignIdx, delta, true}
					}
					feasibleList = append(feasibleList, candidate{assignIdx, delta, true})
				} else {
					ok = false
				}
				dispatch.Assigns[assignIdx].RemoveShip(shipID)
				dispatch.Assigns[assignIdx].GenRoute()
				if !ok {
					dispatch.Assigns[assignIdx].Cost = assignCopyCostBefore
				}
			}
		}
		if bestCandidate.insertOk {
			dispatch.Assigns[bestCandidate.assignIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestCandidate.assignIdx].GenRoute()
			for idx, ai := range feasibleAssignIndices {
				if ai == bestCandidate.assignIdx {
					baseCosts[idx] = dispatch.Assigns[ai].Cost
					break
				}
			}
			continue
		}
		if len(feasibleList) == 0 {
			added := false
			for _, tryIdx := range shuffledSeed {
				if tryIdx >= MAXASSIGNS {
					continue
				}
				if tryIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = tryIdx + 1
				}
				ok := dispatch.Assigns[tryIdx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[tryIdx].GenRoute()
					if dispatch.Assigns[tryIdx].Cost >= 0 {
						baseCosts = append(baseCosts, dispatch.Assigns[tryIdx].Cost)
						feasibleAssignIndices = append(feasibleAssignIndices, tryIdx)
						shuffledSeed = append(shuffledSeed, tryIdx)
						added = true
						break
					} else {
						dispatch.Assigns[tryIdx].RemoveShip(shipID)
						dispatch.Assigns[tryIdx].GenRoute()
					}
				}
			}
			if !added {
				nextNew := dispatch.AssignsLen
				if nextNew < MAXASSIGNS {
					ok := dispatch.Assigns[nextNew].AddShip(shipID, ori, des)
					if ok {
						dispatch.Assigns[nextNew].GenRoute()
						if dispatch.Assigns[nextNew].Cost >= 0 {
							dispatch.AssignsLen++
							baseCosts = append(baseCosts, dispatch.Assigns[nextNew].Cost)
							feasibleAssignIndices = append(feasibleAssignIndices, nextNew)
							shuffledSeed = append(shuffledSeed, nextNew)
						} else {
							dispatch.Assigns[nextNew].RemoveShip(shipID)
							dispatch.Assigns[nextNew].GenRoute()
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

