Greedy insertion with regret-based tie-breaking and sequential empty-slot evaluation, using incremental cost and always falling back to a forced empty assign creation.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIDOffset := range oris {
		ori := oris[shipIDOffset]
		des := dess[shipIDOffset]
		shipID := total_ship + shipIDOffset

		type candidate struct {
			idx       int
			delta     float64
			assign    Assign
			isNewSlot bool
		}
		var candidates []candidate

		// Try all existing assigns
		for i := 0; i < dispatch.AssignsLen; i++ {
			assignCopy := dispatch.Assigns[i]
			oldCost := assignCopy.Cost
			ok := assignCopy.AddShip(shipID, ori, des)
			if ok {
				assignCopy.GenRoute()
				newCost := assignCopy.Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					candidates = append(candidates, candidate{idx: i, delta: delta, assign: assignCopy, isNewSlot: false})
				}
			}
		}

		// Try empty slots
		startEmpty := dispatch.AssignsLen
		if startEmpty < MAXASSIGNS {
			for idx := startEmpty; idx < MAXASSIGNS; idx++ {
				var tmpAssign Assign
				ok := tmpAssign.AddShip(shipID, ori, des)
				if ok {
					tmpAssign.GenRoute()
					if tmpAssign.Cost >= 0 {
						delta := tmpAssign.Cost // cost from empty base
						candidates = append(candidates, candidate{idx: idx, delta: delta, assign: tmpAssign, isNewSlot: true})
					}
				}
			}
		}

		// Select best candidate by smallest delta; if tie, prefer smaller idx
		bestCandidateIdx := -1
		bestDelta := math.MaxFloat64
		for j, cand := range candidates {
			if cand.delta < bestDelta || (cand.delta == bestDelta && cand.idx < candidates[bestCandidateIdx].idx) {
				bestDelta = cand.delta
				bestCandidateIdx = j
			}
		}

		if bestCandidateIdx != -1 {
			bestCand := candidates[bestCandidateIdx]
			dispatch.Assigns[bestCand.idx] = bestCand.assign
			if bestCand.isNewSlot && bestCand.idx >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestCand.idx + 1
			}
		} else {
			// Force fallback: create new empty assign at first available empty slot
			fallbackIdx := -1
			for idx := dispatch.AssignsLen; idx < MAXASSIGNS; idx++ {
				var tmpAssign Assign
				ok := tmpAssign.AddShip(shipID, ori, des)
				if ok {
					tmpAssign.GenRoute()
					if tmpAssign.Cost >= 0 {
						dispatch.Assigns[idx] = tmpAssign
						dispatch.AssignsLen = idx + 1
						fallbackIdx = idx
						break
					}
				}
			}
			if fallbackIdx == -1 {
				// If still impossible, try inserting into existing assign even if cost negative (problem guarantee should avoid this)
				for i := 0; i < dispatch.AssignsLen; i++ {
					assignCopy := dispatch.Assigns[i]
					ok := assignCopy.AddShip(shipID, ori, des)
					if ok {
						assignCopy.GenRoute()
						dispatch.Assigns[i] = assignCopy
						break
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

