Greedy insertion with incremental cost evaluation and fallback to empty assign creation when all existing assigns fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIDOffset := range oris {
		ori := oris[shipIDOffset]
		des := dess[shipIDOffset]
		shipID := total_ship + shipIDOffset

		bestAssignIdx := -1
		bestCostDelta := math.MaxFloat64
		var bestBackupAssign Assign

		// Evaluate all existing non‑empty assigns first
		for i := 0; i < dispatch.AssignsLen; i++ {
			assignCopy := dispatch.Assigns[i]
			oldCost := assignCopy.Cost

			ok := assignCopy.AddShip(shipID, ori, des)
			if ok {
				assignCopy.GenRoute()
				newCost := assignCopy.Cost
				if newCost >= 0 {
					costDelta := newCost - oldCost
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = i
						bestBackupAssign = assignCopy
					}
				}
			}
		}

		// Also evaluate all empty slots (including those beyond current AssignsLen up to MAXASSIGNS)
		if dispatch.AssignsLen < MAXASSIGNS || bestAssignIdx == -1 {
			startEmpty := 0
			if dispatch.AssignsLen < MAXASSIGNS {
				startEmpty = dispatch.AssignsLen
			} else {
				// All slots occupied, still check if any slot is currently unused in practice?
				// We'll treat this case as trying to find an assign with StationsLen==0 among existing ones.
				// But per spec we already tried all existing assigns above, so here we just create a new empty assign if possible.
			}
			for idx := startEmpty; idx < MAXASSIGNS; idx++ {
				if idx >= MAXASSIGNS {
					break
				}
				var tmpAssign Assign
				ok := tmpAssign.AddShip(shipID, ori, des)
				if ok {
					tmpAssign.GenRoute()
					if tmpAssign.Cost >= 0 {
						// Empty assign cost delta is simply its new cost (old cost was zero/nonexistent)
						costDelta := tmpAssign.Cost
						if costDelta < bestCostDelta {
							bestCostDelta = costDelta
							bestAssignIdx = idx
							bestBackupAssign = tmpAssign
						}
					}
				}
				if bestAssignIdx != -1 && bestAssignIdx < MAXASSIGNS && bestAssignIdx >= dispatch.AssignsLen {
					// We found an empty slot better than all existing ones, stop checking further empties? Continue to ensure minimal delta.
				}
			}
		}

		// Apply the best insertion found
		if bestAssignIdx != -1 {
			if bestAssignIdx >= dispatch.AssignsLen {
				dispatch.Assigns[bestAssignIdx] = bestBackupAssign
				dispatch.AssignsLen++
			} else {
				dispatch.Assigns[bestAssignIdx] = bestBackupAssign
			}
		} else {
			// Fallback: force insert into a new empty assign at the end, even if it means extending AssignsLen
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				ok := dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						// Last resort: keep the assign empty (should not happen given problem guarantees)
						dispatch.Assigns[fallbackIdx].RemoveShip(shipID)
						dispatch.Assigns[fallbackIdx].GenRoute()
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

