population.algorithm:
Iterate through orders sequentially, attempt insertion into all existing non-empty assigns first using a cost-based greedy selection, then try empty assigns if needed, always inserting each order somewhere and calling RenewnTotalCost before returning.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for jj := 0; jj < orderCount; jj++ {
		bestIdx := -1
		bestCostIncrease := 1e308
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj
		inserted := false
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			assignCopy := dispatch.Assigns[ii]
			if assignCopy.AddShip(shipID, ori, des) {
				oldCost := assignCopy.Cost
				assignCopy.GenRoute()
				newCost := assignCopy.Cost
				costIncrease := 1e308
				if newCost >= 0 {
					costIncrease = newCost - oldCost
					if costIncrease < bestCostIncrease {
						bestCostIncrease = costIncrease
						bestIdx = ii
					}
				}
				dispatch.Assigns[ii].RemoveShip(shipID)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		if bestIdx >= 0 {
			dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestIdx].GenRoute()
			inserted = true
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				emptyIdx := -1
				for ii := 0; ii < MAXASSIGNS; ii++ {
					found := false
					for k := 0; k < dispatch.AssignsLen; k++ {
						if &dispatch.Assigns[k] == &dispatch.Assigns[ii] {
							found = true
							break
						}
					}
					if !found {
						isTrulyEmpty := true
						if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen > 0 {
							isTrulyEmpty = false
						}
						if isTrulyEmpty {
							emptyIdx = ii
							break
						}
					}
				}
				if emptyIdx < 0 {
					emptyIdx = dispatch.AssignsLen
				}
				if emptyIdx >= MAXASSIGNS {
					emptyIdx = MAXASSIGNS - 1
				}
				if emptyIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = emptyIdx + 1
				}
				if dispatch.Assigns[emptyIdx].AddShip(shipID, ori, des) {
					dispatch.Assigns[emptyIdx].GenRoute()
					inserted = true
				}
			}
		}
		if !inserted {
			fallbackIdx := -1
			for ii := 0; ii < dispatch.AssignsLen; ii++ {
				if dispatch.Assigns[ii].AddShip(shipID, ori, des) {
					dispatch.Assigns[ii].GenRoute()
					fallbackIdx = ii
					break
				}
			}
			if fallbackIdx < 0 && dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				dispatch.Assigns[newIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[newIdx].GenRoute()
				dispatch.AssignsLen++
			} else if fallbackIdx >= 0 {
				dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[fallbackIdx].GenRoute()
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

