Greedy randomized adaptive search with regret-based scoring: evaluate feasible inserts using a combined score of immediate cost increase and regret value (second-best cost difference), select probabilistically from top candidates, otherwise create new assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const alpha = 0.7 // greediness factor
	const candidateSize = 3
	randSeed := uint32(0x12345678)

	for jj := range oris {
		type candidate struct {
			idx     int
			score   float64
			increase float64
		}
		var candidates []candidate
		bestRegretIncrease := 1e308
		secondBestIncrease := 1e308

		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			assignCopy := dispatch.Assigns[ai]
			oldCost := assignCopy.Cost

			if assignCopy.AddShip(total_ship+jj, oris[jj], dess[jj]) {
				assignCopy.GenRoute()
				newCost := assignCopy.Cost

				if newCost >= 0 {
					increase := newCost - oldCost
					candidates = append(candidates, candidate{idx: ai, score: increase, increase: increase})
					if increase < bestRegretIncrease {
						secondBestIncrease = bestRegretIncrease
						bestRegretIncrease = increase
					} else if increase < secondBestIncrease {
						secondBestIncrease = increase
					}
				}
			}
		}

		selectedIdx := -1
		if len(candidates) > 0 {
			regretValue := secondBestIncrease - bestRegretIncrease
			if secondBestIncrease == 1e308 {
				regretValue = 0
			}
			for i := range candidates {
				inc := candidates[i].increase
				combinedScore := inc - alpha*regretValue
				candidates[i].score = combinedScore
			}
			topK := candidateSize
			if len(candidates) < topK {
				topK = len(candidates)
			}
			for i := 0; i < topK; i++ {
				minIdx := i
				for j := i + 1; j < len(candidates); j++ {
					if candidates[j].score < candidates[minIdx].score {
						minIdx = j
					}
				}
				candidates[i], candidates[minIdx] = candidates[minIdx], candidates[i]
			}
			randSeed = randSeed*1664525 + 1013904223
			pickProb := randSeed % 10000
			pickVal := int(pickProb) % topK
			selectedIdx = candidates[pickVal].idx
		}

		if selectedIdx != -1 {
			dispatch.Assigns[selectedIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[selectedIdx].GenRoute()
		} else {
			seedIdx := dispatch.AssignsLen
			if seedIdx < MAXASSIGNS {
				dispatch.Assigns[seedIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
