func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const (
		capacityWeight     = 3.0
		timeWindowWeight   = 2.5
		distanceBaseFactor = 1.0
		penaltyMultiplier  = 10000.0
	)
	type candidate struct {
		assignIdx int
		score     float64
		feasible  bool
	}

	for shipIDOffset := 0; shipIDOffset < len(oris); shipIDOffset++ {
		orderID := total_ship + shipIDOffset
		ori := oris[shipIDOffset]
		des := dess[shipIDOffset]

		var feasibleCandidates []candidate
		bestFallbackScore := 1e18
		bestFallbackIdx := -1

		for aa := 0; aa < dispatch.AssignsLen; aa++ {
			prevCost := dispatch.Assigns[aa].Cost
			added := dispatch.Assigns[aa].AddShip(orderID, ori, des)
			if added {
				dispatch.Assigns[aa].GenRoute()
				newCost := dispatch.Assigns[aa].Cost
				if newCost >= 0 && prevCost >= 0 {
					deltaDistCost := newCost - prevCost
					capacityUtil := 1.0
					loadSum := ori.Load + des.Load
					if loadSum > 0 {
						capacityUtil = float64(loadSum) / 100.0
					}
					timeTightness := 0.0
					if ori.TimeEnd > ori.TimeStart {
						windowSize := ori.TimeEnd - ori.TimeStart
						if windowSize > 0 {
							timeTightness = 10.0 / float64(windowSize)
						}
					}
					score := deltaDistCost*distanceBaseFactor +
						capacityWeight*(deltaDistCost+capacityUtil*penaltyMultiplier/100) +
						timeWindowWeight*timeTightness*penaltyMultiplier/50 -
						float64(aa)*0.01
					feasibleCandidates = append(feasibleCandidates,
						candidate{assignIdx: aa, score: score, feasible: true})
				} else if prevCost < 0 {
					basePenalty := penaltyMultiplier
					if newCost >= 0 {
						basePenalty = 0.0
					}
					distDirect := cal_dis(ori, des)
					score := basePenalty + distDirect*distanceBaseFactor
					if score < bestFallbackScore {
						bestFallbackScore = score
						bestFallbackIdx = aa
					}
				}
				dispatch.Assigns[aa].RemoveShip(orderID)
				dispatch.Assigns[aa].GenRoute()
			}
		}

		inserted := false
		if len(feasibleCandidates) > 0 {
			minScore := 1e18
			bestIdx := -1
			for _, c := range feasibleCandidates {
				if c.score < minScore {
					minScore = c.score
					bestIdx = c.assignIdx
				}
			}
			if bestIdx >= 0 && bestIdx < dispatch.AssignsLen {
				if dispatch.Assigns[bestIdx].AddShip(orderID, ori, des) {
					dispatch.Assigns[bestIdx].GenRoute()
					inserted = true
				}
			}
		}

