func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx          int
		costIncrease float64
	}
	type orderInfo struct {
		orderIdx int
		score    float64
	}
	const EMPTY_THRESHOLD = 10

	allOrders := make([]orderInfo, len(oris))
	for i := range oris {
		dx := dess[i].X - oris[i].X
		dy := dess[i].Y - oris[i].Y
		timeWidth := dess[i].TimeEnd - oris[i].TimeStart
		if timeWidth <= 0 {
			timeWidth = 1
		}
		allOrders[i] = orderInfo{orderIdx: i, score: float64(dx*dx+dy*dy) / float64(timeWidth)}
	}

	sort.SliceStable(allOrders, func(i, j int) bool {
		return allOrders[i].score > allOrders[j].score
	})

	for _, oi := range allOrders {
		j := oi.orderIdx
		bestCandidate := candidate{idx: -1, costIncrease: 1e18}
		secondBestCandidate := candidate{idx: -1, costIncrease: 1e18}
		regretSum := 0.0
		feasibleCount := 0

		for ii := 0; ii < MAXASSIGNS; ii++ {
			if ii >= dispatch.AssignsLen && ii != dispatch.AssignsLen {
