						dispatch.Assigns[ii].RemoveShip(total_ship + j)
						dispatch.Assigns[ii].GenRoute()
					}
				}
				sort.Slice(tempCandidates, func(a, b int) bool {
					return tempCandidates[a].costIncrease < tempCandidates[b].costIncrease
				})
				if len(tempCandidates) > 0 {
					bestCandidate = tempCandidates[0]
					if len(tempCandidates) > 1 {
						secondBestCandidate = tempCandidates[1]
					} else {
						secondBestCandidate = bestCandidate
					}
					if secondBestCandidate.costIncrease-bestCandidate.costIncrease > 30 {
						chosenIdx = bestCandidate.idx
					} else {
						minCostInc := 1e18
						for _, c := range tempCandidates {
							if c.costIncrease < minCostInc {
								minCostInc = c.costIncrease
								chosenIdx = c.idx
							}
						}
					}
				}
			}
		} else if bestCandidate.idx != -1 {
