			}
			sort.Slice(sortedEmptyIndices, func(a, b int) bool {
				stA := Station{X: 0, Y: 0, TimeStart: 0, TimeEnd: 86400, ReqCode: 0, Load: 0}
				stB := Station{X: 0, Y: 0, TimeStart: 0, TimeEnd: 86400, ReqCode: 0, Load: 0}
				disA := cal_dis(stA, oris[j])
				disB := cal_dis(stB, oris[j])
				return disA < disB
			})
			inserted := false
			for _, idx := range sortedEmptyIndices {
