population.algorithm:
Greedy insertion with regret-based parallel evaluation: process all remaining orders simultaneously, compute regret values by comparing best and second-best feasible insertions across existing routes, prioritize orders with highest regret, use cheapest insertion position, and create new routes only when necessary.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	type candidateInfo struct {
		routeIdx int
		delta    float64
		feasible bool
	}
	unassigned := make([]int, orderCount)
	for i := range unassigned {
		unassigned[i] = i
	}
	for len(unassigned) > 0 {
		bestRegret := -1.0
		selectedOrderIdx := -1
		var selectedCandidates []candidateInfo
		for _, u := range unassigned {
			candidates := make([]candidateInfo, dispatch.AssignsLen+1)
			for i := 0; i < dispatch.AssignsLen; i++ {
				oldCost := dispatch.Assigns[i].Cost
				id := total_ship + u
				ok := dispatch.Assigns[i].AddShip(id, oris[u], dess[u])
				if ok {
					newCost := dispatch.Assigns[i].Cost
					candidates[i] = candidateInfo{i, newCost - oldCost, true}
					dispatch.Assigns[i].RemoveShip(id)
					dispatch.Assigns[i].GenRoute()
				} else {
					candidates[i] = candidateInfo{-1, 1e308, false}
				}
			}
			var best, secondBest *candidateInfo
			for ci := 0; ci < dispatch.AssignsLen; ci++ {
				if candidates[ci].feasible {
					if best == nil || candidates[ci].delta < best.delta {
						secondBest = best
						best = &candidates[ci]
					} else if secondBest == nil || candidates[ci].delta < secondBest.delta {
						secondBest = &candidates[ci]
					}
				}
			}
			regret := 0.0
			bc := best
			sc := secondBest
			if bc != nil {
				if sc != nil {
					regret = sc.delta - bc.delta
				} else {
					regret = 1e307
				}
			}
			if bc != nil && regret > bestRegret {
				bestRegret = regret
				selectedOrderIdx = u
				selectedCandidates = candidates
			}
		}
		if selectedOrderIdx >= 0 {
			inserted := false
			bc := (*candidateInfo)(nil)
			for ci := 0; ci < dispatch.AssignsLen; ci++ {
				if selectedCandidates[ci].feasible {
					if bc == nil || selectedCandidates[ci].delta < bc.delta {
						bc = &selectedCandidates[ci]
					}
				}
			}
			if bc != nil {
				id := total_ship + selectedOrderIdx
				dispatch.Assigns[bc.routeIdx].AddShip(id, oris[selectedOrderIdx], dess[selectedOrderIdx])
				dispatch.Assigns[bc.routeIdx].GenRoute()
				inserted = true
			}
			if !inserted {
				if dispatch.AssignsLen < MAXASSIGNS {
					id := total_ship + selectedOrderIdx
					ok := dispatch.Assigns[dispatch.AssignsLen].AddShip(id, oris[selectedOrderIdx], dess[selectedOrderIdx])
					if ok {
						dispatch.Assigns[dispatch.AssignsLen].GenRoute()
						dispatch.AssignsLen++
						inserted = true
					}
				}
			}
			if !inserted {
				for ii := 0; ii < dispatch.AssignsLen; ii++ {
					if dispatch.Assigns[ii].StationsLen == 0 {
						id := total_ship + selectedOrderIdx
						ok := dispatch.Assigns[ii].AddShip(id, oris[selectedOrderIdx], dess[selectedOrderIdx])
						if ok {
							dispatch.Assigns[ii].GenRoute()
							inserted = true
							break
						}
					}
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				id := total_ship + selectedOrderIdx
				ok := dispatch.Assigns[dispatch.AssignsLen].AddShip(id, oris[selectedOrderIdx], dess[selectedOrderIdx])
				if ok {
					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
					dispatch.AssignsLen++
				}
			}
			newUnassigned := make([]int, 0, len(unassigned)-1)
			for _, idx := range unassigned {
				if idx != selectedOrderIdx {
					newUnassigned = append(newUnassigned, idx)
				}
			}
			unassigned = newUnassigned
		} else {
			for _, u := range unassigned {
				inserted := false
				if dispatch.AssignsLen < MAXASSIGNS {
					id := total_ship + u
					ok := dispatch.Assigns[dispatch.AssignsLen].AddShip(id, oris[u], dess[u])
					if ok {
