New algorithm: Greedy insertion with regret heuristic and fallback to best feasible empty assign using time window proximity sorting.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx          int
		costIncrease float64
	}
	type orderInfo struct {
		orderIdx int
		score    float64
	}
	const EMPTY_THRESHOLD = 10

	allOrders := make([]orderInfo, len(oris))
	for i := range oris {
		dx := dess[i].X - oris[i].X
		dy := dess[i].Y - oris[i].Y
		timeWidth := dess[i].TimeEnd - oris[i].TimeStart
		if timeWidth <= 0 {
			timeWidth = 1
		}
		allOrders[i] = orderInfo{orderIdx: i, score: float64(dx*dx+dy*dy) / float64(timeWidth)}
	}

	sort.SliceStable(allOrders, func(i, j int) bool {
		return allOrders[i].score > allOrders[j].score
	})

	for _, oi := range allOrders {
		j := oi.orderIdx
		bestCandidate := candidate{idx: -1, costIncrease: 1e18}
		secondBestCandidate := candidate{idx: -1, costIncrease: 1e18}
		regretSum := 0.0
		feasibleCount := 0

		for ii := 0; ii < MAXASSIGNS; ii++ {
			if ii >= dispatch.AssignsLen && ii != dispatch.AssignsLen {
				continue
			}
			oldCost := dispatch.Assigns[ii].Cost
			if oldCost < 0 && ii < dispatch.AssignsLen {
				continue
			}
			addOk := false
			if ii < dispatch.AssignsLen {
				addOk = dispatch.Assigns[ii].AddShip(total_ship+j, oris[j], dess[j])
			} else if ii == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[ii].StationCurrent = Station{X: 0, Y: 0, TimeStart: 0, TimeEnd: 86400, ReqCode: 0, Load: 0}
				dispatch.Assigns[ii].Cost = 0.0
				addOk = dispatch.Assigns[ii].AddShip(total_ship+j, oris[j], dess[j])
			}
			if addOk {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				increase := newCost - oldCost
				if increase < 0 {
					increase = 0
				}
				if increase < bestCandidate.costIncrease {
					secondBestCandidate = bestCandidate
					bestCandidate = candidate{idx: ii, costIncrease: increase}
				} else if increase < secondBestCandidate.costIncrease {
					secondBestCandidate = candidate{idx: ii, costIncrease: increase}
				}
				feasibleCount++
				dispatch.Assigns[ii].RemoveShip(total_ship + j)
				dispatch.Assigns[ii].GenRoute()
			} else if ii < dispatch.AssignsLen {
				dispatch.Assigns[ii].RemoveShip(total_ship + j)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		chosenIdx := -1
		if bestCandidate.idx != -1 && feasibleCount > 1 {
			if secondBestCandidate.idx != -1 {
				regretSum = secondBestCandidate.costIncrease - bestCandidate.costIncrease
			} else {
				regretSum = bestCandidate.costIncrease
			}
			if regretSum > 50 || feasibleCount <= 2 {
				chosenIdx = bestCandidate.idx
			} else {
				tempCandidates := []candidate{}
				for ii := 0; ii < MAXASSIGNS; ii++ {
					if ii >= dispatch.AssignsLen && ii != dispatch.AssignsLen {
						continue
					}
					oldCost := dispatch.Assigns[ii].Cost
					if oldCost < 0 && ii < dispatch.AssignsLen {
						continue
					}
					addOk := false
					if ii < dispatch.AssignsLen {
						addOk = dispatch.Assigns[ii].AddShip(total_ship+j, oris[j], dess[j])
					} else if ii == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
						dispatch.Assigns[ii].StationCurrent = Station{X: 0, Y: 0, TimeStart: 0, TimeEnd: 86400, ReqCode: 0, Load: 0}
						dispatch.Assigns[ii].Cost = 0.0
						addOk = dispatch.Assigns[ii].AddShip(total_ship+j, oris[j], dess[j])
					}
					if addOk {
						dispatch.Assigns[ii].GenRoute()
						newCost := dispatch.Assigns[ii].Cost
						increase := newCost - oldCost
						if increase < 0 {
							increase = 0
						}
						tempCandidates = append(tempCandidates, candidate{idx: ii, costIncrease: increase})
						dispatch.Assigns[ii].RemoveShip(total_ship + j)
						dispatch.Assigns[ii].GenRoute()
					} else if ii < dispatch.AssignsLen {
						dispatch.Assigns[ii].RemoveShip(total_ship + j)
						dispatch.Assigns[ii].GenRoute()
					}
				}
				sort.Slice(tempCandidates, func(a, b int) bool {
					return tempCandidates[a].costIncrease < tempCandidates[b].costIncrease
				})
				if len(tempCandidates) > 0 {
					bestCandidate = tempCandidates[0]
					if len(tempCandidates) > 1 {
						secondBestCandidate = tempCandidates[1]
					} else {
						secondBestCandidate = bestCandidate
					}
					if secondBestCandidate.costIncrease-bestCandidate.costIncrease > 30 {
						chosenIdx = bestCandidate.idx
					} else {
						minCostInc := 1e18
						for _, c := range tempCandidates {
							if c.costIncrease < minCostInc {
								minCostInc = c.costIncrease
								chosenIdx = c.idx
							}
						}
					}
				}
			}
		} else if bestCandidate.idx != -1 {
			chosenIdx = bestCandidate.idx
		}

		if chosenIdx == -1 {
			sortedEmptyIndices := make([]int, 0, MAXASSIGNS-dispatch.AssignsLen+1)
			for ii := dispatch.AssignsLen; ii < MAXASSIGNS; ii++ {
				sortedEmptyIndices = append(sortedEmptyIndices, ii)
			}
			sort.Slice(sortedEmptyIndices, func(a, b int) bool {
				stA := Station{X: 0, Y: 0, TimeStart: 0, TimeEnd: 86400, ReqCode: 0, Load: 0}
				stB := Station{X: 0, Y: 0, TimeStart: 0, TimeEnd: 86400, ReqCode: 0, Load: 0}
				disA := cal_dis(stA, oris[j])
				disB := cal_dis(stB, oris[j])
				return disA < disB
			})
			inserted := false
			for _, idx := range sortedEmptyIndices {
				if idx >= MAXASSIGNS {
					continue
				}
				dispatch.Assigns[idx].StationCurrent = Station{X: 0, Y: 0, TimeStart: 0, TimeEnd: 86400, ReqCode: 0, Load: 0}
				dispatch.Assigns[idx].Cost = 0.0
				if dispatch.Assigns[idx].AddShip(total_ship+j, oris[j], dess[j]) {
					dispatch.Assigns[idx].GenRoute()
					if dispatch.Assigns[idx].Cost >= 0 {
						chosenIdx = idx
						inserted = true
						break
					} else {
						dispatch.Assigns[idx].RemoveShip(total_ship + j)
						dispatch.Assigns[idx].GenRoute()
					}
				}
			}
			if !inserted {
				for ii := 0; ii < dispatch.AssignsLen; ii++ {
					if dispatch.Assigns[ii].Cost < 0 {
						continue
					}
					addOk := dispatch.Assigns[ii].AddShip(total_ship+j, oris[j], dess[j])
					if addOk {
						dispatch.Assigns[ii].GenRoute()
						if dispatch.Assigns[ii].Cost >= 0 {
							chosenIdx = ii
							inserted = true
							break
						} else {
							dispatch.Assigns[ii].RemoveShip(total_ship + j)
							dispatch.Assigns[ii].GenRoute()
						}
					} else {
						dispatch.Assigns[ii].RemoveShip(total_ship + j)
						dispatch.Assigns[ii].GenRoute()
					}
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].StationCurrent = Station{X: 0, Y: 0, TimeStart: 0, TimeEnd: 86400, ReqCode: 0, Load: 0}
				dispatch.Assigns[dispatch.AssignsLen].Cost = 0.0
				if dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship+j, oris[j], dess[j]) {
					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
					if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
						chosenIdx = dispatch.AssignsLen
						inserted = true
					} else {
						dispatch.Assigns[dispatch.AssignsLen].RemoveShip(total_ship + j)
						dispatch.Assigns[dispatch.AssignsLen].GenRoute()
					}
				}
			}
			if inserted && chosenIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = chosenIdx + 1
			}
		}

		if chosenIdx != -1 {
			if chosenIdx >= dispatch.AssignsLen {
				dispatch.Assigns[chosenIdx].StationCurrent = Station{X: 0, Y: 0, TimeStart: 0, TimeEnd: 86400, ReqCode: 0, Load: 0}
				dispatch.Assigns[chosenIdx].Cost = 0.0
				dispatch.AssignsLen = chosenIdx + 1
			}
			addOk := dispatch.Assigns[chosenIdx].AddShip(total_ship+j, oris[j], dess[j])
			if addOk {
				dispatch.Assigns[chosenIdx].GenRoute()
				if dispatch.Assigns[chosenIdx].Cost < 0 {
					dispatch.Assigns[chosenIdx].RemoveShip(total_ship + j)
					dispatch.Assigns[chosenIdx].GenRoute()
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

