						dispatch.Assigns[idx].RemoveShip(total_ship + j)
						dispatch.Assigns[idx].GenRoute()
					}
				}
			}
			if !inserted {
				for ii := 0; ii < dispatch.AssignsLen; ii++ {
					if dispatch.Assigns[ii].Cost < 0 {
						continue
					}
					addOk := dispatch.Assigns[ii].AddShip(total_ship+j, oris[j], dess[j])
					if addOk {
						dispatch.Assigns[ii].GenRoute()
						if dispatch.Assigns[ii].Cost >= 0 {
							chosenIdx = ii
							inserted = true
							break
						} else {
							dispatch.Assigns[ii].RemoveShip(total_ship + j)
							dispatch.Assigns[ii].GenRoute()
						}
					} else {
						dispatch.Assigns[ii].RemoveShip(total_ship + j)
						dispatch.Assigns[ii].GenRoute()
					}
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].StationCurrent = Station{X: 0, Y: 0, TimeStart: 0, TimeEnd: 86400, ReqCode: 0, Load: 0}
				dispatch.Assigns[dispatch.AssignsLen].Cost = 0.0
				if dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship+j, oris[j], dess[j]) {
					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
					if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
						chosenIdx = dispatch.AssignsLen
						inserted = true
					} else {
						dispatch.Assigns[dispatch.AssignsLen].RemoveShip(total_ship + j)
						dispatch.Assigns[dispatch.AssignsLen].GenRoute()
					}
				}
			}
			if inserted && chosenIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = chosenIdx + 1
			}
		}

		if chosenIdx != -1 {
			if chosenIdx >= dispatch.AssignsLen {
				dispatch.Assigns[chosenIdx].StationCurrent = Station{X: 0, Y: 0, TimeStart: 0, TimeEnd: 86400, ReqCode: 0, Load: 0}
				dispatch.Assigns[chosenIdx].Cost = 0.0
				dispatch.AssignsLen = chosenIdx + 1
			}
			addOk := dispatch.Assigns[chosenIdx].AddShip(total_ship+j, oris[j], dess[j])
			if addOk {
				dispatch.Assigns[chosenIdx].GenRoute()
				if dispatch.Assigns[chosenIdx].Cost < 0 {
					dispatch.Assigns[chosenIdx].RemoveShip(total_ship + j)
					dispatch.Assigns[chosenIdx].GenRoute()
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
}
